findings.suggestion:
BEFORE:
case 'sse': {
  if (!config.url) throw new Error('sse transport requires "url"')
  return { type: 'sse' as const, url: config.url, ...(config.headers && { headers: config.headers }) }
}
case 'http': {
  if (!config.url) throw new Error('http transport requires "url"')
  return { type: 'http' as const, url: config.url, ...(config.headers && { headers: config.headers }) }
}

AFTER:
case 'sse':
case 'http': {
  if (!config.url) throw new Error(`${config.transport} transport requires "url"`)
  return { type: config.transport as 'sse' | 'http', url: config.url, ...(config.headers && { headers: config.headers }) }
}

WHY: Eliminates a near-duplicate 9-line block. The two cases have identical logic; only the type literal differs, which can be derived from config.transport. Fall-through case grouping is a standard pattern for identical branches.

